// =====================================================
// Village — the central region.
// Edges:  east -> forest.map     (walk off the right)
//         north -> road.map      (walk off the top)
// =====================================================

part Garden {
  size 5, 5;
  fill DIRT from (0,0) to (4,4);
  tile FLOWER at (0,0);
  tile FLOWER at (4,0);
  tile FLOWER at (0,4);
  tile FLOWER at (4,4);
  tile FLOWER at (2,2);
}

part Homestead {
  size 5, 5;
  tile HOUSE at (2,2);
  tile FENCE at (0,4);
  tile FENCE at (1,4);
  tile FENCE at (2,4);
  tile FENCE at (3,4);
  tile FENCE at (4,4);
  tile FENCE at (0,0);
  tile FENCE at (0,1);
  tile FENCE at (0,2);
  tile FENCE at (0,3);
}

part Pond {
  size 3, 3;
  fill WATER from (0,0) to (2,2);
  tile ROCK at (0,0);
}

part LitGate {
  size 3, 1;
  tile TORCH at (0,0);
  tile PATH  at (1,0);
  tile TORCH at (2,0);
}

map Village {
  size 20, 14;

  neighbor east  "forest.map";
  neighbor north "road.map";

  // Main road running east-west across the village
  row PATH from (0,7) to (19,7);

  // Houses
  place Homestead at (3,1);
  place Homestead at (12,1);

  // Garden in the middle
  place Garden at (7,1);

  // Pond in the south
  place Pond at (4,10);

  // Lit gate at the east edge — the threshold to the forest
  place LitGate at (17,7);

  player at (2,8);
}
